import { createClient } from '@supabase/supabase-js';
import type { Database } from './types';

// Get environment variables with fallbacks
const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const SUPABASE_PUBLISHABLE_KEY = import.meta.env.VITE_SUPABASE_ANONYMOUS_KEY;

// Check if environment variables are defined
if (!SUPABASE_URL) {
  console.error('VITE_SUPABASE_URL is undefined. Please check your environment variables.');
  console.error('Make sure to create a .env file with VITE_SUPABASE_URL and VITE_SUPABASE_ANONYMOUS_KEY');
}
if (!SUPABASE_PUBLISHABLE_KEY) {
  console.error('VITE_SUPABASE_ANONYMOUS_KEY is undefined. Please check your environment variables.');
}

// Debug environment variables
console.log('Supabase URL:', SUPABASE_URL);
console.log('Supabase Key exists:', !!SUPABASE_PUBLISHABLE_KEY);
console.log('Environment mode:', import.meta.env.MODE);

// Validate URL format
if (SUPABASE_URL && !SUPABASE_URL.startsWith('http')) {
  console.error('Invalid Supabase URL format. Must start with http:// or https://');
}

// Create client with proper error handling
let supabase;
try {
  if (!SUPABASE_URL || !SUPABASE_PUBLISHABLE_KEY) {
    throw new Error('Missing required Supabase environment variables');
  }
  supabase = createClient<Database>(SUPABASE_URL, SUPABASE_PUBLISHABLE_KEY);
} catch (error) {
  console.error('Failed to create Supabase client:', error);
  // Create a dummy client for development
  supabase = createClient<Database>('https://placeholder.supabase.co', 'placeholder-key');
}

export { supabase };